import React, { useEffect, useState } from "react";
import axios from "axios";
import { Bar, Pie } from "react-chartjs-2";
import './AdminDashboard.css';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);

const AdminDashboard = () => {
  const [predictions, setPredictions] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get("http://localhost:5000/admin/dashboard");
        setPredictions(res.data.predictions || []);
      } catch (err) {
        console.error("Error fetching data:", err);
      }
    };
    fetchData();
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  const totalUsers = predictions.length;
  const salaries = predictions.map(p => p.salary).filter(s => s != null);
  const avgSalary = salaries.length ? (salaries.reduce((a, b) => a + b, 0) / salaries.length) : 0;
  const highestSalary = salaries.length ? Math.max(...salaries) : 0;
  const lowestSalary = salaries.length ? Math.min(...salaries) : 0;
JavaScript
const chartOptions = {
  responsive: true,
  maintainAspectRatio: false, // Allows the chart to fill the .chart-box height
  plugins: {
    legend: {
      position: 'bottom',
      labels: { padding: 10 }
    }
  }
  };

  const barData = {
    labels: ["<40k", "40-60k", "60-80k", "80-100k", ">100k"],
    datasets: [{
      label: 'Predictions',
      data: [
        predictions.filter(p => p.salary < 40000).length,
        predictions.filter(p => p.salary >= 40000 && p.salary < 60000).length,
        predictions.filter(p => p.salary >= 60000 && p.salary < 80000).length,
        predictions.filter(p => p.salary >= 80000 && p.salary < 100000).length,
        predictions.filter(p => p.salary >= 100000).length,
      ],
      backgroundColor: '#3b82f6',
      borderRadius: 5
    }]
  };

  const pieData = {
    labels: ["Exp", "Entry", "Int", "Post"],
    datasets: [{
      data: [
        predictions.filter(p => p.experience === "Experienced").length || 1,
        predictions.filter(p => p.experience === "Entry").length || 1,
        predictions.filter(p => p.experience === "Intermediate").length || 1,
        predictions.filter(p => p.experience === "Post-Graduate").length || 1
      ],
      backgroundColor: ["#6366f1", "#f59e0b", "#10b981", "#ef4444"]
    }]
  };

  return (
    <div className="admin-view">
      {/* SIDEBAR */}
      <aside className="sidebar-container">
        <div className="sidebar-profile">
          <div className="avatar">👤</div>
          <h3>Admin</h3>
        </div>
        <nav className="sidebar-nav">
          <div className="nav-link active">Dashboard</div>
          <div className="nav-link">Users</div>
          <div className="nav-link">Reports</div>
          <div className="nav-link">Settings</div>
        </nav>
        <button className="logout-btn" onClick={handleLogout}>Logout</button>
      </aside>

      {/* MAIN CONTENT */}
      <main className="content-area">
        <header className="content-header">
          <h2>Admin Dashboard</h2>
          <div className="header-icons">🔔 👤</div>
        </header>

        <div className="scrollable-content">
          {/* STATS */}
          <section className="stats-container">
            <div className="stat-item c1"><span>Avg Salary</span><h2>₹{avgSalary.toLocaleString()}</h2></div>
            <div className="stat-item c2"><span>Highest</span><h2>₹{highestSalary.toLocaleString()}</h2></div>
            <div className="stat-item c3"><span>Lowest</span><h2>₹{lowestSalary.toLocaleString()}</h2></div>
            <div className="stat-item c4"><span>Total Users</span><h2>{totalUsers}</h2></div>
          </section>

          {/* CHARTS */}
          <section className="charts-container">
            <div className="chart-card">
              <h4>Salary Distribution</h4>
              <div className="chart-box"><Bar data={barData} options={chartOptions} /></div>
            </div>
            <div className="chart-card">
              <h4>Experience Level</h4>
              <div className="chart-box"><Pie data={pieData} options={chartOptions} /></div>
            </div>
          </section>

          {/* TABLE */}
          <section className="table-container">
            <h4>Recent Predictions</h4>
            <div className="table-responsive">
              <table className="custom-table">
                <thead>
                  <tr><th>Email</th><th>Role</th><th>Location</th><th>Salary</th></tr>
                </thead>
                <tbody>
                  {predictions.slice(-3).reverse().map((p, i) => (
                    <tr key={i}>
                      <td>{p.email}</td>
                      <td>{p.role}</td>
                      <td>{p.location}</td>
                      <td className="bold-price">₹{p.salary?.toLocaleString()}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
